Here's a production-grade thread pool with work stealing:

```cpp
// ThreadPool.h
#pragma once

#include <vector>
#include <queue>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <future>
#include <functional>
#include <atomic>
#include <memory>
#include <optional>
#include <span>
#include <concepts>
#include <coroutine>
#include <random>

namespace async {

enum class TaskPriority : uint8_t {
    LOW = 0,
    NORMAL = 1,
    HIGH = 2,
    CRITICAL = 3,
};

struct TaskInfo {
    std::function<void()> func;
    TaskPriority priority;
    std::string name;
    std::chrono::steady_clock::time_point created_at;

    bool operator<(const TaskInfo& other) const {
        if (priority != other.priority) {
            return static_cast<int>(priority) < static_cast<int>(other.priority);
        }
        return created_at > other.created_at;
    }
};

class WorkStealingQueue {
public:
    void push(TaskInfo task) {
        std::lock_guard lock(mutex_);
        queue_.push(std::move(task));
        cv_.notify_one();
    }

    std::optional<TaskInfo> try_pop() {
        std::lock_guard lock(mutex_);
        if (queue_.empty()) return std::nullopt;
        auto task = std::move(const_cast<TaskInfo&>(queue_.top()));
        queue_.pop();
        return task;
    }

    std::optional<TaskInfo> try_steal() {
        std::lock_guard lock(mutex_);
        if (queue_.empty()) return std::nullopt;
        // Steal from the back (oldest) for better cache behavior
        std::vector<TaskInfo> temp;
        while (!queue_.empty()) {
            temp.push_back(const_cast<TaskInfo&>(queue_.top()));
            queue_.pop();
        }
        if (temp.empty()) return std::nullopt;
        auto task = std::move(temp.back());
        temp.pop_back();
        for (auto& t : temp) {
            queue_.push(std::move(t));
        }
        return task;
    }

    [[nodiscard]] bool empty() const {
        std::lock_guard lock(mutex_);
        return queue_.empty();
    }

    [[nodiscard]] size_t size() const {
        std::lock_guard lock(mutex_);
        return queue_.size();
    }

private:
    mutable std::mutex mutex_;
    std::priority_queue<TaskInfo> queue_;
    std::condition_variable cv_;
};

class ThreadPool {
public:
    explicit ThreadPool(
        size_t num_threads = std::thread::hardware_concurrency(),
        std::string_view name = "ThreadPool"
    ) : stop_(false), active_tasks_(0), name_(name) {
        queues_.resize(num_threads);
        for (size_t i = 0; i < num_threads; ++i) {
            queues_[i] = std::make_unique<WorkStealingQueue>();
        }

        for (size_t i = 0; i < num_threads; ++i) {
            workers_.emplace_back([this, i] { worker_loop(i); });
        }
    }

    ~ThreadPool() {
        stop();
    }

    // Submit a task and get a future
    template<typename F, typename... Args>
    auto submit(
        F&& f,
        Args&&... args,
        TaskPriority priority = TaskPriority::NORMAL,
        std::string_view name = ""
    ) -> std::future<std::invoke_result_t<F, Args...>> {
        using ReturnType = std::invoke_result_t<F, Args...>;

        auto task = std::make_shared<std::packaged_task<ReturnType()>>(
            std::bind(std::forward<F>(f), std::forward<Args>(args)...)
        );

        auto future = task->get_future();

        TaskInfo info{
            [task]() { (*task)(); },
            priority,
            std::string(name),
            std::chrono::steady_clock::now()
        };

        // Round-robin assignment
        size_t queue_idx = next_queue_.fetch_add(1) % queues_.size();
        queues_[queue_idx]->push(std::move(info));

        return future;
    }

    // Submit a void task
    template<typename F, typename... Args>
    void submit_void(
        F&& f,
        Args&&... args,
        TaskPriority priority = TaskPriority::NORMAL,
        std::string_view name = ""
    ) {
        TaskInfo info{
            std::bind(std::forward<F>(f), std::forward<Args>(args)...),
            priority,
            std::string(name),
            std::chrono::steady_clock::now()
        };

        size_t queue_idx = next_queue_.fetch_add(1) % queues_.size();
        queues_[queue_idx]->push(std::move(info));
    }

    // Wait for all tasks to complete
    void wait_all() {
        while (active_tasks_.load() > 0) {
            std::this_thread::yield();
        }
    }

    // Stop the thread pool
    void stop() {
        stop_.store(true);
        for (auto& queue : queues_) {
            // Push sentinel tasks
            queue->push({[]() {}, TaskPriority::LOW, "stop", {}});
        }
        for (auto& worker : workers_) {
            if (worker.joinable()) worker.join();
        }
    }

    [[nodiscard]] size_t thread_count() const { return workers_.size(); }
    [[nodiscard]] std::string_view name() const { return name_; }

    // Get stats
    struct Stats {
        size_t total_threads;
        size_t active_tasks;
        std::vector<size_t> queue_sizes;
    };

    Stats stats() const {
        Stats s;
        s.total_threads = workers_.size();
        s.active_tasks = active_tasks_.load();
        s.queue_sizes.reserve(queues_.size());
        for (auto& q : queues_) {
            s.queue_sizes.push_back(q->size());
        }
        return s;
    }

private:
    void worker_loop(size_t thread_id) {
        std::mt19937 rng(thread_id);

        while (!stop_.load()) {
            TaskInfo task;
            bool found = false;

            // Try local queue first
            if (auto t = queues_[thread_id]->try_pop()) {
                task = std::move(*t);
                found = true;
            }

            // Work stealing: try random other queues
            if (!found) {
                size_t num_queues = queues_.size();
                std::uniform_int_distribution<size_t> dist(0, num_queues - 1);

                for (size_t attempt = 0; attempt < num_queues * 2 && !found; ++attempt) {
                    size_t steal_idx = rng() % num_queues;
                    if (steal_idx == thread_id) continue;
                    if (auto t = queues_[steal_idx]->try_steal()) {
                        task = std::move(*t);
                        found = true;
                    }
                }
            }

            if (found) {
                active_tasks_.fetch_add(1);
                task.func();
                active_tasks_.fetch_sub(1);
            } else {
                std::this_thread::sleep_for(std::chrono::microseconds(100));
            }
        }
    }

    std::vector<std::unique_ptr<WorkStealingQueue>> queues_;
    std::vector<std::thread> workers_;
    std::atomic<bool> stop_;
    std::atomic<size_t> active_tasks_;
    std::atomic<size_t> next_queue_{0};
    std::string name_;
};

} // namespace async

// Usage example
/*
#include "ThreadPool.h"
#include <iostream>

int main() {
    async::ThreadPool pool(4, "MainPool");

    // Submit tasks with different priorities
    auto future1 = pool.submit([] {
        return 42;
    }, TaskPriority::HIGH, "answer");

    auto future2 = pool.submit([](int a, int b) {
        return a + b;
    }, 10, 20, TaskPriority::NORMAL, "addition");

    pool.submit_void([] {
        std::cout << "Background task\n";
    }, TaskPriority::LOW, "background");

    std::cout << "Result 1: " << future1.get() << "\n";
    std::cout << "Result 2: " << future2.get() << "\n";

    pool.wait_all();
    return 0;
}
*/
