```cpp
// LockFreeHashMap.h
#pragma once

#include <atomic>
#include <cstdint>
#include <cstring>
#include <memory>
#include <optional>
#include <span>
#include <functional>
#include <immintrin.h>

namespace concurrent {

// Cache line size for false sharing prevention
constexpr size_t CACHE_LINE_SIZE = 64;

template<typename Key, typename Value, typename Hash = std::hash<Key>>
class LockFreeHashMap {
    struct alignas(CACHE_LINE_SIZE) Slot {
        std::atomic<uint64_t> key_hash{0};
        Key key{};
        Value value{};
        std::atomic<bool> occupied{false};
        std::atomic<bool> deleted{false};

        Slot() = default;
        Slot(const Key& k, const Value& v, uint64_t h)
            : key_hash(h), key(k), value(v), occupied(true), deleted(false) {}
    };

public:
    explicit LockFreeHashMap(size_t capacity = 1024)
        : capacity_(next_power_of_two(capacity))
        , mask_(capacity_ - 1)
        , table_(std::make_unique<Slot[]>(capacity_))
        , size_(0) {}

    ~LockFreeHashMap() = default;

    // Non-copyable, movable
    LockFreeHashMap(const LockFreeHashMap&) = delete;
    LockFreeHashMap& operator=(const LockFreeHashMap&) = delete;
    LockFreeHashMap(LockFreeHashMap&&) = default;
    LockFreeHashMap& operator=(LockFreeHashMap&&) = default;

    // Insert or update
    bool insert(const Key& key, const Value& value) {
        uint64_t hash = hash_fn_(key);
        size_t idx = hash & mask_;

        for (size_t probe = 0; probe < capacity_; ++probe) {
            Slot& slot = table_[(idx + probe) & mask_];

            uint64_t slot_hash = slot.key_hash.load(std::memory_order_acquire);

            if (slot_hash == 0) {
                // Empty slot - try to insert
                if (slot.occupied.compare_exchange_strong(
                        reinterpret_cast<std::atomic<bool>&>(slot_hash),
                        true,
                        std::memory_order_acq_rel,
                        std::memory_order_acquire)) {
                    slot.key_hash.store(hash, std::memory_order_release);
                    slot.key = key;
                    slot.value = value;
                    slot.deleted.store(false, std::memory_order_release);
                    size_.fetch_add(1, std::memory_order_relaxed);
                    return true;
                }
            }

            if (slot_hash == hash && slot.occupied.load(std::memory_order_acquire)) {
                // Same hash - check key
                if (slot.key == key) {
                    // Update existing
                    slot.value = value;
                    slot.deleted.store(false, std::memory_order_release);
                    return true;
                }
            }
        }
        return false; // Table full
    }

    // Insert using CAS for lock-free behavior
    bool insert_cas(const Key& key, const Value& value) {
        uint64_t hash = hash_fn_(key);
        size_t idx = hash & mask_;

        for (size_t probe = 0; probe < capacity_; ++probe) {
            Slot& slot = table_[(idx + probe) & mask_];

            uint64_t expected_hash = 0;
            if (slot.key_hash.compare_exchange_strong(
                    expected_hash, hash,
                    std::memory_order_acq_rel,
                    std::memory_order_acquire)) {
                slot.key = key;
                slot.value = value;
                slot.occupied.store(true, std::memory_order_release);
                slot.deleted.store(false, std::memory_order_release);
                size_.fetch_add(1, std::memory_order_relaxed);
                return true;
            }

            if (expected_hash == hash &&
                slot.occupied.load(std::memory_order_acquire) &&
                !slot.deleted.load(std::memory_order_acquire) &&
                slot.key == key) {
                slot.value = value;
                return true;
            }
        }
        return false;
    }

    // Lookup
    std::optional<Value> find(const Key& key) const {
        uint64_t hash = hash_fn_(key);
        size_t idx = hash & mask_;

        for (size_t probe = 0; probe < capacity_; ++probe) {
            const Slot& slot = table_[(idx + probe) & mask_];
            uint64_t slot_hash = slot.key_hash.load(std::memory_order_acquire);

            if (slot_hash == 0) return std::nullopt; // Empty = not found

            if (slot_hash == hash &&
                slot.occupied.load(std::memory_order_acquire) &&
                !slot.deleted.load(std::memory_order_acquire) &&
                slot.key == key) {
                return slot.value;
            }
        }
        return std::nullopt;
    }

    // Erase (logical deletion)
    bool erase(const Key& key) {
        uint64_t hash = hash_fn_(key);
        size_t idx = hash & mask_;

        for (size_t probe = 0; probe < capacity_; ++probe) {
            Slot& slot = table_[(idx + probe) & mask_];
            uint64_t slot_hash = slot.key_hash.load(std::memory_order_acquire);

            if (slot_hash == 0) return false;

            if (slot_hash == hash &&
                slot.occupied.load(std::memory_order_acquire) &&
                !slot.deleted.load(std::memory_order_acquire) &&
                slot.key == key) {
                slot.deleted.store(true, std::memory_order_release);
                size_.fetch_sub(1, std::memory_order_relaxed);
                return true;
            }
        }
        return false;
    }

    // Get current size
    [[nodiscard]] size_t size() const {
        return size_.load(std::memory_order_relaxed);
    }

    [[nodiscard]] bool empty() const { return size() == 0; }

    // Iterate (snapshot - may miss concurrent inserts)
    template<typename F>
    void for_each(F&& func) const {
        for (size_t i = 0; i < capacity_; ++i) {
            const Slot& slot = table_[i];
            if (slot.occupied.load(std::memory_order_acquire) &&
                !slot.deleted.load(std::memory_order_acquire)) {
                func(slot.key, slot.value);
            }
        }
    }

private:
    static size_t next_power_of_two(size_t n) {
        n--;
        n |= n >> 1;
        n |= n >> 2;
        n |= n >> 4;
        n |= n >> 8;
        n |= n >> 16;
        n |= n >> 32;
        return n + 1;
    }

    size_t capacity_;
    size_t mask_;
    std::unique_ptr<Slot[]> table_;
    std::atomic<size_t> size_;
    Hash hash_fn_{};
};

} // namespace concurrent

// Usage:
/*
#include "LockFreeHashMap.h"
#include <string>
#include <iostream>

int main() {
    concurrent::LockFreeHashMap<std::string, int> map(4096);

    // Concurrent inserts
    map.insert("hello", 42);
    map.insert("world", 100);

    auto val = map.find("hello");
    if (val) std::cout << "Found: " << *val << "\n";

    map.erase("hello");
    std::cout << "Size: " << map.size() << "\n";
}
*/
