use middleware::{Middleware, LoggerMiddleware, CorsMiddleware};
use response::{Response, StatusCode};

pub struct AppState {
    pub db: Arc<RwLock<HashMap<String, Value>>>,
    pub start_time: u64,
}

impl AppState {
    pub fn new() -> Self {
        Self {
            db: Arc::new(RwLock::new(HashMap::new())),
            start_time: SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap()
                .as_secs(),
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let state = Arc::new(AppState::new());

    let mut router = Router::new(state.clone());

    // Register routes
    router.get("/", handle_index);
    router.get("/health", handle_health);
    router.get("/api/users", handle_get_users);
    router.post("/api/users", handle_create_user);
    router.get("/api/users/:id", handle_get_user);
    router.put("/api/users/:id", handle_update_user);
    router.delete("/api/users/:id", handle_delete_user);
    router.get("/ws", handle_websocket);

    // Add middleware
    router.use(LoggerMiddleware::new());
    router.use(CorsMiddleware::new().allow_all());

    let listener = TcpListener::bind("0.0.0.0:8080").await?;
    println!("Server running on http://0.0.0.0:8080");

    loop {
        let (stream, addr) = listener.accept().await?;
        let state = state.clone();
        let router = router.clone();

        tokio::spawn(async move {
            if let Err(e) = handle_connection(stream, state, router).await {
                eprintln!("Error handling {}: {}", addr, e);
            }
        });
    }
}

async fn handle_connection(
    mut stream: TcpStream,
    state: Arc<AppState>,
    router: Router,
) -> Result<(), Box<dyn std::error::Error>> {
    let mut buffer = vec![0u8; 8192];
    let n = stream.read(&mut buffer).await?;
    if n == 0 { return Ok(()); }

    let request = String::from_utf8_lossy(&buffer[..n]);
    let response = router.handle(&request, &state).await;

    stream.write_all(response.to_bytes().as_ref()).await?;
    stream.flush().await?;

    Ok("
}

// Route handlers
async fn handle_index(_req: &str, _state: &AppState) -> Response {
    Response::json(json!({
        "name": "Rust HTTP Server",
        "version": "1.0.0",
        "endpoints": ["/health", "/api/users", "/ws"]
    }))
}

async fn handle_health(_req: &str, state: &AppState) -> Response {
    let uptime = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs() - state.start_time;

    Response::json(json!({
        "status": "healthy",
        "uptime_seconds": uptime,
        "memory_usage_mb": get_memory_usage(),
    }))
}

async fn handle_get_users(_req: &str, state: &AppState) -> Response {
    let db = state.db.read().await;
    let users: Vec<&Value> = db.values().collect();
    Response::json(json!({ "users": users }))
}

async fn handle_create_user(req: &str, state: &AppState) -> Response {
    let body = extract_json_body(req);
    let name = body.get("name").and_then(|v| v.as_str()).unwrap_or("");
    let email = body.get("email").and_then(|v| v.as_str()).unwrap_or("");

    if name.is_empty() || email.is_empty() {
        return Response::error(StatusCode::BAD_REQUEST, "Name and email required");
    }

    let id = uuid::Uuid::new_v4().to_string();
    let user = json!({
        "id": id,
        "name": name,
        "email": email,
        "created_at": chrono::Utc::now().to_rfc3339(),
    });

    state.db.write().await.insert(id.clone(), user.clone());
    Response::created(user)
}

async fn handle_get_user(req: &str, state: &AppState) -> Response {
    let id = extract_param(req, ":id");
    let db = state.db.read().await;

    match db.get(&id) {
        Some(user) => Response::json(user.clone()),
        None => Response::error(StatusCode::NOT_FOUND, "User not found"),
    }
}

async fn handle_update_user(req: &str, state: &AppState) -> Response {
    let id = extract_param(req, ":id");
    let body = extract_json_body(req);
    let mut db = state.db.write().await;

    match db.get_mut(&id) {
        Some(user) => {
            if let Some(name) = body.get("name").and_then(|v| v.as_str()) {
                user["name"] = json!(name);
            }
            if let Some(email) = body.get("email").and_then(|v| v.as_str()) {
                user["email"] = json!(email);
            }
            Response::json(user.clone())
        }
        None => Response::error(StatusCode::NOT_FOUND, "User not found"),
    }
}

async fn handle_delete_user(req: &str, state: &AppState) -> Response {
    let id = extract_param(req, ":id");
    let mut db = state.db.write().await;
    db.remove(&id);
    Response::ok()
}

async fn handle_websocket(req: &str, _state: &AppState) -> Response {
    // WebSocket upgrade response
    let key = extract_ws_key(req);
    let accept_key = websocket::compute_accept_key(&key);

    Response::builder()
        .status(StatusCode::SWITCHING_PROTOCOLS)
        .header("Upgrade", "websocket")
        .header("Connection", "Upgrade")
        .header("Sec-WebSocket-Accept", &accept_key)
        .build()
}

fn extract_json_body(req: &str) -> Value {
    let parts: Vec<&str> = req.split("\r\n\r\n").collect();
    if parts.len() > 1 {
        serde_json::from_str(parts[1]).unwrap_or(json!({}))
    } else {
        json!({})
    }
}

fn extract_param(req: &str, param: &str) -> String {
    let lines: Vec<&str> = req.lines().collect();
    if let Some(line) = lines.first() {
        let parts: Vec<&str> = line.split_whitespace().collect();
        if parts.len() >= 2 {
            let path = parts[1];
            let segments: Vec<&str> = path.split('/').collect();
            for (i, seg) in segments.iter().enumerate() {
                if *seg == param.trim_start_matches(':') {
                    return segments.get(i + 1).unwrap_or(&"").to_string();
                }
            }
        }
    }
    String::new()
}

fn extract_ws_key(req: &str) -> String {
    for line in req.lines() {
        if line.to_lowercase().starts_with("sec-websocket-key:") {
            return line.splitn(2, ':').nth(1).unwrap_or("").trim().to_string();
        }
    }
    String::new()
}

fn get_memory_usage() -> u64 {
    #[cfg(target_os = "linux")]
    {
        use std::fs;
        let status = fs::read_to_string("//proc//self//status").unwrap_or_default();
        for line in status.lines() {
            if line.starts_with("VmRSS:") {
                let kb: u64 = line.split_whitespace().nth(1).unwrap_or("0").parse().unwrap_or(0);
                return kb / 1024;
            }
        }
    }
    0
}
