// src/router.rs
use std::collections::HashMap;
use std::sync::Arc;
use crate::{AppState, Response, StatusCode};
use crate::middleware::Middleware;

pub type Handler = Arc<dyn Fn(&str, &AppState) -> futures::future::BoxFuture<'static, Response> + Send + Sync>;

#[derive(Clone)]
pub struct Router {
    routes: Vec<Route>,
    middlewares: Vec<Arc<dyn Middleware>>,
    state: Arc<AppState>,
}

pub struct Route {
    pub method: String,
    pub path: String,
    pub handler: Handler,
}

impl Router {
    pub fn new(state: Arc<AppState>) -> Self {
        Self {
            routes: Vec::new(),
            middlewares: Vec::new(),
            state,
        }
    }

    pub fn get(&mut self, path: &str, handler: impl Fn(&str, &AppState) -> futures::future::BoxFuture<'static, Response> + Send + Sync + 'static) {
        self.routes.push(Route {
            method: "GET".to_string(),
            path: path.to_string(),
            handler: Arc::new(handler),
        });
    }

    pub fn post(&mut self, path: &str, handler: impl Fn(&str, &AppState) -> futures::future::BoxFuture<'static, Response> + Send + Sync + 'static) {
        self.routes.push(Route {
            method: "POST".to_string(),
            path: path.to_string(),
            handler: Arc::new(handler),
        });
    }

    pub fn put(&mut self, path: &str, handler: impl Fn(&str, &AppState) -> futures::future::BoxFuture<'static, Response> + Send + Sync + 'static) {
        self.routes.push(Route {
            method: "PUT".to_string(),
            path: path.to_string(),
            handler: Arc::new(handler),
        });
    }

    pub fn delete(&mut self, path: &str, handler: impl Fn(&str, &AppState) -> futures::future::BoxFuture<'static, Response> + Send + Sync + 'static) {
        self.routes.push(Route {
            method: "DELETE".to_string(),
            path: path.to_string(),
            handler: Arc::new(handler),
        });
    }

    pub fn use_middleware(&mut self, mw: impl Middleware + 'static) {
        self.middlewares.push(Arc::new(mw));
    }

    pub async fn handle(&self, request: &str, state: &AppState) -> Response {
        let method = extract_method(request);
        let path = extract_path(request);

        for route in &self.routes {
            if route.method == method && routes_match(&route.path, &path) {
                return (route.handler)(request, state).await;
            }
        }

        Response::error(StatusCode::NOT_FOUND, "Route not found")
    }
}

fn extract_method(request: &str) -> String {
    request.split_whitespace().next().unwrap_or("").to_string()
}

fn extract_path(request: &str) -> String {
    request.split_whitespace().nth(1).unwrap_or("/").to_string()
}

fn routes_match(pattern: &str, path: &str) -> bool {
    let pattern_parts: Vec<&str> = pattern.split('/').collect();
    let path_parts: Vec<&str> = path.split('/').collect();
    if pattern_parts.len() != path_parts.len() { return false; }
    for (p, a) in pattern_parts.iter().zip(path_parts.iter()) {
        if p.starts_with(':') { continue; }
        if p != a { return false; }
    }
    true
}
