package ratelimiter

import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/redis/go-redis/v9"
)

type Limiter interface {
	Allow(ctx context.Context, key string) (bool, *LimitInfo, error)
	AllowN(ctx context.Context, key string, n int) (bool, *LimitInfo, error)
}

type LimitInfo struct {
	Allowed   bool
	Remaining int
	ResetAt   time.Time
	Limit     int
}

// TokenBucket implements token bucket algorithm
struct TokenBucket struct {
	client     *redis.Client
	rate       int           // tokens per second
	burst      int           // max tokens
	keyPrefix  string
	fallback   *LocalLimiter // fallback when Redis is down
}

func NewTokenBucket(client *redis.Client, rate, burst int, keyPrefix string) *TokenBucket {
	return &TokenBucket{
		client:    client,
		rate:      rate,
		burst:     burst,
		keyPrefix: keyPrefix,
		fallback:  NewLocalLimiter(rate, burst),
	}
}

// Lua script for atomic token bucket
var tokenBucketScript = redis.NewScript(`
local key = KEYS[1]
local rate = tonumber(ARGV[1])
local burst = tonumber(ARGV[2])
local now = tonumber(ARGV[3])
local requested = tonumber(ARGV[4])

local bucket = redis.call('HMGET', key, 'tokens', 'last_refill')
local tokens = tonumber(bucket[1]) or burst
local last_refill = tonumber(bucket[2]) or now

-- Refill tokens
local elapsed = now - last_refill
local refill = elapsed * rate
tokens = math.min(burst, tokens + refill)

-- Try to consume
if tokens >= requested then
    tokens = tokens - requested
    redis.call('HMSET', key, 'tokens', tokens, 'last_refill', now)
    redis.call('EXPIRE', key, math.ceil(burst / rate) + 1)
    return {1, tokens, math.ceil((burst - tokens) / rate)}
else
    redis.call('HMSET', key, 'tokens', tokens, 'last_refill', now)
    redis.call('EXPIRE', key, math.ceil(burst / rate) + 1)
    return {0, tokens, 0}
end
`)

func (tb *TokenBucket) Allow(ctx context.Context, key string) (bool, *LimitInfo, error) {
	return tb.AllowN(ctx, key, 1)
}

func (tb *TokenBucket) AllowN(ctx context.Context, key string, n int) (bool, *LimitInfo, error) {
	fullKey := fmt.Sprintf("%s:%s", tb.keyPrefix, key)
	now := time.Now().UnixMilli()

	result, err := tokenBucketScript.Run(ctx, tb.client, []string{fullKey},
		tb.rate, tb.burst, now, n,
	).Int64Slice()

	if err != nil {
		// Fallback to local limiter
		allowed := tb.fallback.AllowN(key, n)
		return allowed, &LimitInfo{
			Allowed:   allowed,
			Remaining: tb.burst,
			ResetAt:   time.Now().Add(time.Second),
			Limit:     tb.burst,
		}, nil
	}

	allowed := result[0] == 1
	remaining := int(result[1])
	resetIn := time.Duration(result[2]) * time.Second

	return allowed, &LimitInfo{
		Allowed:   allowed,
		Remaining: remaining,
		ResetAt:   time.Now().Add(resetIn),
		Limit:     tb.burst,
	}, nil
}
