// ratelimiter/local.go
package ratelimiter

import (
	"sync"
	"time"
)

// LocalLimiter provides in-memory rate limiting when Redis is unavailable
type LocalLimiter struct {
	mu       sync.RWMutex
	buckets  map[string]*localBucket
	rate     int
	burst    int
}

type localBucket struct {
	tokens    float64
	lastRefill time.Time
}

func NewLocalLimiter(rate, burst int) *LocalLimiter {
	l := &LocalLimiter{
		buckets: make(map[string]*localBucket),
		rate:    rate,
		burst:   burst,
	}
	go l.cleanup()
	return l
}

func (l *LocalLimiter) AllowN(key string, n int) bool {
	l.mu.Lock()
	defer l.mu.Unlock()

	bucket, exists := l.buckets[key]
	if !exists {
		bucket = &localBucket{
			tokens:    float64(l.burst),
			lastRefill: time.Now(),
		}
		l.buckets[key] = bucket
	}

	// Refill
	elapsed := time.Since(bucket.lastRefill).Seconds()
	bucket.tokens = min(float64(l.burst), bucket.tokens+elapsed*float64(l.rate))
	bucket.lastRefill = time.Now()

	// Consume
	if bucket.tokens >= float64(n) {
		bucket.tokens -= float64(n)
		return true
	}
	return false
}

func (l *LocalLimiter) cleanup() {
	ticker := time.NewTicker(time.Minute)
	for range ticker.C {
		l.mu.Lock()
		for key, bucket := range l.buckets {
			if time.Since(bucket.lastRefill) > 5*time.Minute {
				delete(l.buckets, key)
			}
		}
		l.mu.Unlock()
	}
}
